import{c as e,Q as r,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Anthropic: April 23 Postmortem — Claude Code Quality Incident","description":"","frontmatter":{"url":"https://www.anthropic.com/engineering/april-23-postmortem","date":"2026-05-09T00:00:00.000Z","source":"Anthropic Official Engineering Blog","tags":["postmortem","Claude-Code","harness-regression","prompt-change-impact","model-stability"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-anthropic-april-23-postmortem-claude-code-quality.md","filePath":"research/ai-articles/scored/2026-05-09-anthropic-april-23-postmortem-claude-code-quality.md","lastUpdated":1779796674000}'),i={name:"research/ai-articles/scored/2026-05-09-anthropic-april-23-postmortem-claude-code-quality.md"};function l(s,t,n,c,d,p){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="anthropic-april-23-postmortem-—-claude-code-quality-incident" tabindex="-1">Anthropic: April 23 Postmortem — Claude Code Quality Incident <a class="header-anchor" href="#anthropic-april-23-postmortem-—-claude-code-quality-incident" aria-label="Permalink to &quot;Anthropic: April 23 Postmortem — Claude Code Quality Incident&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.anthropic.com/engineering/april-23-postmortem" target="_blank" rel="noreferrer">https://www.anthropic.com/engineering/april-23-postmortem</a><br><strong>作者</strong>：Anthropic Team<br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>2026 年 3-4 月，Anthropic 遇到 Claude Code 品質下滑；根本原因非模型退化，而是三項 harness 變更累積：(1) reasoning effort default 改為 medium、(2) prompt caching bug 導致 thinking history 反覆清除、(3) 系統提示加入字數限制。修復後，團隊引入「per-model evaluation suite」+ 「system prompt ablation」來防止類似回歸。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Harness 變更單獨可能不可見，累積則致命</strong></p><ul><li>單一改動：reasoning effort medium → 可能接受的速度-品質權衡</li><li>但與 cache bug + prompt 字數限制一起，品質下降 3%</li><li>用戶感知：「模型變蠢了」；實際：harness 三維退化</li></ul></li><li><p><strong>Cache Bug 的隱形殺傷</strong></p><ul><li>原意：清除舊 thinking sections 避免 cache 膨脹</li><li>實際：每次 turn 都清除 thinking history</li><li>結果：模型「失去記憶為何選擇該路徑」→ cascading reasoning 失敗</li></ul></li><li><p><strong>System Prompt 字數限制反直覺的影響</strong></p><ul><li>看似無害的「keep responses under word count」</li><li>實際：reduce coding quality by 3% across both Opus versions</li><li>未在內部測試中被捕捉（testing on development variant vs. production）</li></ul></li><li><p><strong>Post-Training Harness Coupling 的脆性</strong></p><ul><li>Opus 4.6/4.7 被 trained on 「specific reasoning effort levels, specific prompt structure, specific cache behavior」</li><li>Harness 改變後，模型在新環境下的有效能力下滑</li><li>Implication：模型和 harness 已共進化到難以解耦的程度</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>「Per-Model Evaluation Suite」對 cc-workspace 必要性</strong></p><ul><li>當前 <code>.claude/refs/quality.md</code> 提及 <code>bash scripts/healthcheck.sh</code>，但未區分 Haiku/Sonnet/Opus 的差異</li><li>Anthropic 的教訓：每個模型版本的 harness 假設不同</li><li>建議擴展 healthcheck：為每個模型版本維持獨立的 test case 套組</li></ul></li><li><p><strong>System Prompt Ablation 作為變更守門人</strong></p><ul><li>新增規則或改動 CLAUDE.md 時，應執行「this change × each model」的 ablation</li><li>即：在 Haiku + current-harness、Sonnet + current-harness、Opus + current-harness 上各測一遍</li><li><code>.claude/rules/core.md</code> 現有「git commit message 必含 session URL」，可補充「system prompt 變更需 ablation」</li></ul></li><li><p><strong>Reasoning Effort 的模型特定性</strong></p><ul><li>Postmortem 提及「revert to xhigh for Opus 4.7, high for others」</li><li>cc-workspace 當前 <code>.claude/refs/haiku-pilot/SKILL.md</code> + <code>.claude/refs/opus-pilot/SKILL.md</code> 各有 reasoning effort 推薦</li><li>驗證點：Sonnet 4.6 的推薦 effort level 有無明確記錄？</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接示教「harness 改變如何致使模型表現下滑」；per-model ablation 可直接套用</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>根本原因分析本身非創新；但「多個 harness 改動累積效應」值得論述</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>時間線明確、三項根本原因清晰；無量化數據（僅「3%」一筆）</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>Cache bug 機制清晰；缺乏對「為何字數限制影響編碼」的深入機制分析</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>Harness 改變風險適用任何 agent 系統；Anthropic-specific 的實施細節</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.8/10</strong></td><td>9×0.3 + 6×0.2 + 8×0.2 + 7×0.15 + 8×0.15 = 2.7+1.2+1.6+1.05+1.2 = 7.75</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（補充進 <code>.claude/rules/core.md</code> 的新段 「System Prompt Changes: Per-Model Ablation Requirement」）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>Anthropic harness-design-long-running-apps：harness 元件隨模型成熟過時</li><li><code>.claude/refs/opus-pilot/SKILL.md</code>：Reasoning effort 配置</li><li><code>.claude/rules/core.md</code>：系統提示變更流程</li></ul>',19)])])}const m=e(i,[["render",l]]);export{u as __pageData,m as default};
